#include<bits/stdc++.h>
using namespace std;
bool v[105][105][105];
queue<int> q[4];
char c[105][105];
int t[105][105], n, cnt = 1, maxx, ans;
int fen[105];
int dx[] = {0, -1, 0, 1};
int dy[] = {1, 0, -1, 0};
void bfs() {
	while (!q[0].empty()) {
		int x = q[0].front();
		int y = q[1].front();
		int step = q[2].front();
		int dui = q[3].front();
		q[0].pop();
		q[1].pop();
		q[2].pop();
		q[3].pop();
		for (int i = 0; i < 4; i++) {
			int mx = x + dx[i];
			int my = y + dy[i];
			if (mx <= 0 || my <= 0 || mx > n || my > n || c[mx][my] == '#') continue;
			if (c[mx][my] == '.' && !v[mx][my][dui]) {
				v[mx][my][dui] = 1;
				q[0].push(mx);
				q[1].push(my);
				q[2].push(step + 1);
				q[3].push(dui);
			}
			if (c[mx][my] == '$' && (step + 1 == t[mx][my] || t[mx][my] == 0) && !v[mx][my][dui]) {
				if (t[mx][my] == 0) {
					t[mx][my] = step + 1;
				}
				fen[dui]++;
				v[mx][my][dui] = 1;
				q[0].push(mx);
				q[1].push(my);
				q[2].push(step + 1);
				q[3].push(dui);

			}
		}
	}
	return;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cin >> c[i][j];
			if (c[i][j] == '@') {
				q[0].push(i);
				q[1].push(j);
				q[2].push(0);
				q[3].push(cnt);
				cnt++;
			}
		}
	}
	bfs();
	for (int i = 1; i < cnt; i++) {
		ans += fen[i];
		maxx = max(fen[i], maxx);
	}
	cout << maxx << '\n' << ans;
	return 0;
}
